Greedy insertion with penalized detour scoring considering both distance increase and time-window urgency, evaluating all feasible inserts across all assigns including empties, committing the minimum penalty insert per order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	n := len(oris)
	for oi := 0; oi < n; oi++ {
		bestPenalty := 1e100
		bestAi := -1
		var bestSaved Assign
		foundFeasible := false
		for ai := 0; ai < MAXASSIGNS; ai++ {
			if ai >= dispatch.AssignsLen && ai > dispatch.AssignsLen {
				continue
			}
			assign := &dispatch.Assigns[ai]
			saved := *assign
			ok := assign.AddShip(total_ship+oi, oris[oi], dess[oi])
			if !ok {
				*assign = saved
				continue
			}
			assign.GenRoute()
			if assign.Cost < 0 {
				assign.RemoveShip(total_ship + oi)
				*assign = saved
				continue
			}
			distanceIncrease := assign.Cost - saved.Cost
			timeUrgency := 0.0
			if oris[oi].TimeStart < dess[oi].TimeStart {
				timeUrgency = float64(dess[oi].TimeStart - oris[oi].TimeStart)
			} else {
				timeUrgency = float64(oris[oi].TimeStart - dess[oi].TimeStart)
			}
			penalty := distanceIncrease + 0.3*timeUrgency
			if penalty < bestPenalty {
				bestPenalty = penalty
				bestAi = ai
				bestSaved = saved
				foundFeasible = true
			}
			assign.RemoveShip(total_ship + oi)
			*assign = saved
		}
		if foundFeasible {
			target := &dispatch.Assigns[bestAi]
			if bestAi >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestAi + 1
			}
			target.RemoveShip(total_ship + oi)
			*target = bestSaved
			target.AddShip(total_ship+oi, oris[oi], dess[oi])
			target.GenRoute()
		} else {
			fallbackAi := dispatch.AssignsLen
			if fallbackAi >= MAXASSIGNS {
				fallbackAi = MAXASSIGNS - 1
			}
			target := &dispatch.Assigns[fallbackAi]
			savedFallback := *target
			ok := target.AddShip(total_ship+oi, oris[oi], dess[oi])
			if ok {
				target.GenRoute()
